import React from 'react';
import styled from 'styled-components';

const SectionTitle = styled.h4`
  font-size: 12pt;
  line-height: 12pt;
  position: relative;
  margin-bottom: .1in;
  width: 100%;
  border-bottom: solid 1px #000;

  @media (max-width: 900px) {
    font-size: 9pt;
    line-height: 9pt;
    margin-bottom: .025in;
  }
  @media (max-width: 660px) {
    font-size: 8pt;
    line-height: 8pt;
    margin-bottom: .05in;
  }
  @media print {
    font-size: 12pt;
    line-height: 12pt;
    margin-bottom: .1in;
  }
`;

const SectionContent = styled.div`
  margin: 0in 0in 0in .25in;

  @media (max-width: 900px) {
    margin: 0in 0in 0in .2in;
  }
  @media (max-width: 660px) {
    margin: 0in 0in 0in .125in;
  }
  @media print {
    margin: 0in 0in 0in .25in;
  }
`;

const Skill = styled.div`
  display: inline-block;
  border: solid 1px #000;
  padding: .02in .1in .02in .1in;
  margin: .02in;
  height: .3in;
  min-width: .5in;
  text-align: center;

  @media (max-width: 900px) {
    font-size: 9pt;
    padding: .008in .08in .008in .08in;
    margin: .015in;
    height: .225in;
    min-width: .375in;
  }
  @media (max-width: 660px) {
    font-size: 6pt;
    padding: .005in .05in .005in .05in;
    margin: .01in;
    height: .15in;
    min-width: .25in;
  }
  @media print {
    padding: .02in .1in .02in .1in;
    margin: .02in;
    height: .3in;
    min-width: .5in;
  }
`;

const PrimarySkill = styled(Skill)`
  background-color: #AAA;
  border-top-left-radius: 12pt;
  border-bottom-left-radius: 12pt;
  ${props => props.$isLast && `
    border-top-right-radius: 12pt;
    border-bottom-right-radius: 12pt;
  `}

  @media (max-width: 900px) {
    border-top-left-radius: 9pt;
    border-bottom-left-radius: 9pt;
    ${props => props.$isLast && `
      border-top-right-radius: 9pt;
      border-bottom-right-radius: 9pt;
    `}
  }
  @media (max-width: 660px) {
    border-top-left-radius: 6pt;
    border-bottom-left-radius: 6pt;
    ${props => props.$isLast && `
      border-top-right-radius: 6pt;
      border-bottom-right-radius: 6pt;
    `}
  }
  @media print {
    border-top-left-radius: 12pt;
    border-bottom-left-radius: 12pt;
    ${props => props.$isLast && `
      border-top-right-radius: 12pt;
      border-bottom-right-radius: 12pt;
    `}
  }
`;

const SecondarySkill = styled(Skill)`
  background-color: #CCC;
  ${props => props.$isLast && `
    border-top-right-radius: 12pt;
    border-bottom-right-radius: 12pt;
  `}

  @media (max-width: 900px) {
    ${props => props.$isLast && `
      border-top-right-radius: 9pt;
      border-bottom-right-radius: 9pt;
    `}
  }
  @media (max-width: 660px) {
    ${props => props.$isLast && `
      border-top-right-radius: 6pt;
      border-bottom-right-radius: 6pt;
    `}
  }
  @media print {
    ${props => props.$isLast && `
      border-top-right-radius: 12pt;
      border-bottom-right-radius: 12pt;
    `}
  }
`;

export const Skills = ({ skills }) => {
  return (
    <section>
      <SectionTitle>Skills</SectionTitle>
      <SectionContent>
        {skills.map((skill, index) => {
          const hasFrameworks = skill.frameworks.length > 0;
          const isLastSkill = !hasFrameworks;

          return (
            <React.Fragment key={index}>
              <PrimarySkill $isLast={isLastSkill}>{skill.name}</PrimarySkill>
              {skill.frameworks.map((fw, i) => (
                <SecondarySkill key={i} $isLast={i === skill.frameworks.length - 1}>
                  {fw}
                </SecondarySkill>
              ))}
            </React.Fragment>
          );
        })}
      </SectionContent>
    </section>
  );
};
